prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?messageRef ?messageName ?sourceRef ?targetRef ?choreo WHERE {
  ?model a bboExt:Model .
  FILTER(STRENDS(STR(?model), "4fba0078103d44d9846d4fbec51710cb")) .

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?mf a bboExt:MessageFlow .
  ?mf tai:belongsTo ?choreo .

  OPTIONAL { ?mf bboExt:messageRef ?messageRef . }
  OPTIONAL { ?mf bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?mf bboExt:targetRef ?targetRef . }

  OPTIONAL {
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo ;
         bbo:name ?messageName .
    ?msg bbo:id ?messageId .
    FILTER(BOUND(?messageRef) && ?messageId = ?messageRef)
  }

  FILTER(BOUND(?messageRef) || (BOUND(?sourceRef) && BOUND(?targetRef)))
}
ORDER BY ?messageRef ?messageName ?sourceRef ?targetRef
LIMIT 500

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId ?created WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(
    CONTAINS(LCASE(STR(?model)), LCASE("4fba0078103d44d9846d4fbec51710cb")) ||
    (BOUND(?origId) && CONTAINS(LCASE(STR(?origId)), LCASE("4fba0078103d44d9846d4fbec51710cb"))) ||
    (BOUND(?normId) && CONTAINS(LCASE(STR(?normId)), LCASE("4fba0078103d44d9846d4fbec51710cb"))) ||
    (BOUND(?modelName) && CONTAINS(LCASE(STR(?modelName)), LCASE("4fba0078103d44d9846d4fbec51710cb")))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?choreo) AS ?choreoCount)
       (COUNT(DISTINCT ?mf) AS ?messageFlowCount)
       (COUNT(DISTINCT ?msg) AS ?messageCount)
       (COUNT(DISTINCT ?assoc) AS ?assocCount)
       (COUNT(DISTINCT ?task) AS ?taskCount)
WHERE {
  ?model a bboExt:Model .
  FILTER(CONTAINS(LCASE(STR(?model)), "4fba0078103d44d9846d4fbec51710cb"))

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  OPTIONAL { ?mf a bboExt:MessageFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?msg a bboExt:Message ; tai:belongsTo ?choreo . }
  OPTIONAL { ?assoc a bboExt:Association ; tai:belongsTo ?choreo . }
  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
}
